import{_ as e,a as t,b as i,c as o}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as n,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Aggiungere un canale Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/yandex.md","filePath":"it-IT/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"it-IT/upload/yandex.md"};function c(p,a,h,g,u,m){return d(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="aggiungere-un-canale-yandex" tabindex="-1">Aggiungere un canale Yandex <a class="header-anchor" href="#aggiungere-un-canale-yandex" aria-label="Permalink to &quot;Aggiungere un canale Yandex&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Yandex</td><td>Per accedere e autorizzare Yandex Disk</td></tr><tr><td>App OAuth Yandex</td><td>Per generare <code>Client ID</code> e <code>Client Secret</code></td></tr><tr><td>Dominio ImgBed</td><td>Per l&#39;URI di redirect OAuth</td></tr><tr><td>Spazio Yandex Disk disponibile</td><td>Archivio effettivo dei file</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-crea-un-app-oauth-yandex" tabindex="-1">Passaggio 1: crea un&#39;app OAuth Yandex <a class="header-anchor" href="#passaggio-1-crea-un-app-oauth-yandex" aria-label="Permalink to &quot;Passaggio 1: crea un&#39;app OAuth Yandex&quot;">​</a></h3><ol><li>Apri la pagina di creazione app OAuth Yandex:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Se vieni reindirizzato al login, accedi prima con il tuo account Yandex.</li><li>Crea una nuova app.</li><li>Dai all&#39;app un nome riconoscibile, per esempio <code>imgbed-yandex</code>.</li><li>Trova le impostazioni callback o redirect URL.</li><li>Inserisci:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="passaggio-2-conferma-i-permessi" tabindex="-1">Passaggio 2: conferma i permessi <a class="header-anchor" href="#passaggio-2-conferma-i-permessi" aria-label="Permalink to &quot;Passaggio 2: conferma i permessi&quot;">​</a></h3><p>Per l&#39;attuale integrazione Yandex di ImgBed, mantieni questi quattro permessi sotto <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permesso</th><th>Scopo</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Permette a ImgBed di salvare file nella cartella dell&#39;app</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Legge file e link di download</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Carica file, crea cartelle ed elimina file</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Legge quota disco e spazio usato</td></tr></tbody></table><p>Se sotto <code>Yandex ID API</code> vedi anche questi permessi, sono opzionali:</p><table tabindex="0"><thead><tr><th>Testo permesso</th><th>Consiglio</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Opzionale</td></tr><tr><td><code>Access to email address</code></td><td>Opzionale</td></tr></tbody></table><p>Upload, download, eliminazione e quote dipendono soprattutto dai quattro permessi <code>Yandex.Disk REST API</code> indicati sopra.</p><p><img src="'+e+'" alt="Configura permessi Yandex Disk" loading="lazy"></p><h3 id="passaggio-3-copia-le-credenziali-dell-app" tabindex="-1">Passaggio 3: copia le credenziali dell&#39;app <a class="header-anchor" href="#passaggio-3-copia-le-credenziali-dell-app" aria-label="Permalink to &quot;Passaggio 3: copia le credenziali dell&#39;app&quot;">​</a></h3><p>Dopo aver creato l&#39;app, copia:</p><table tabindex="0"><thead><tr><th>Campo Yandex</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Annota Client ID e Secret" loading="lazy"></p><h3 id="passaggio-4-compila-il-canale-yandex" tabindex="-1">Passaggio 4: compila il canale Yandex <a class="header-anchor" href="#passaggio-4-compila-il-canale-yandex" aria-label="Permalink to &quot;Passaggio 4: compila il canale Yandex&quot;">​</a></h3><p>In Impostazioni di caricamento scegli <code>Yandex</code> e compila:</p><table tabindex="0"><thead><tr><th>Campo ImgBed</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome riconoscibile, per esempio <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> dell&#39;app Yandex</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> dell&#39;app Yandex</td></tr><tr><td>Refresh Token</td><td>Lascialo vuoto per ora</td></tr><tr><td>Directory radice</td><td>Opzionale. Default <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Modifica configurazione canale" loading="lazy"></p><h3 id="passaggio-5-ottieni-il-refresh-token" tabindex="-1">Passaggio 5: ottieni il Refresh Token <a class="header-anchor" href="#passaggio-5-ottieni-il-refresh-token" aria-label="Permalink to &quot;Passaggio 5: ottieni il Refresh Token&quot;">​</a></h3><ol><li>In ImgBed clicca su <code>Get Token</code>.</li><li>Accedi con l&#39;account Yandex da collegare.</li><li>Approva la richiesta di autorizzazione.</li><li>La pagina di callback mostrerà un <code>Refresh Token</code>.</li><li>Copialo.</li><li>Torna in ImgBed e incollalo nel campo <code>Refresh Token</code>.</li></ol><p><img src="'+o+`" alt="Copia Refresh Token dopo l&#39;autorizzazione" loading="lazy"></p><h3 id="passaggio-6-salva-il-canale" tabindex="-1">Passaggio 6: salva il canale <a class="header-anchor" href="#passaggio-6-salva-il-canale" aria-label="Permalink to &quot;Passaggio 6: salva il canale&quot;">​</a></h3><p>Quando tutti i campi sono compilati, salva il canale.</p><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Crea un&#39;app</span></span>
<span class="line"><span>-&gt; Aggiungi https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Conferma i permessi Yandex Disk</span></span>
<span class="line"><span>-&gt; Copia Client ID e Client Secret</span></span>
<span class="line"><span>-&gt; Inserisci Client ID / Client Secret in ImgBed</span></span>
<span class="line"><span>-&gt; Clicca Get Token</span></span>
<span class="line"><span>-&gt; Copia il Refresh Token dalla pagina di callback</span></span>
<span class="line"><span>-&gt; Incollalo in ImgBed e salva</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Registrare un&#39;app Yandex: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Ottenere un authorization code via URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Endpoint token OAuth Yandex: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=n(r,[["render",c]]);export{f as __pageData,k as default};
